import { WorkflowContext, StepOutput } from 'mastra/workflows';
import { VexClient } from '@vex_dev/sdk';

const vex = new VexClient({ apiKey: process.env.VEX_API_KEY! });

export async function detectWorkflowHallucination(ctx: WorkflowContext, output: StepOutput): Promise<boolean> {
  const prevOutput = ctx.history[ctx.history.length - 2];
  if (!prevOutput) return true;

  const result = await vex.checkHallucination({
    prompt: output.content,
    context: prevOutput.content,
    threshold: 0.7
  });

  if (result.isHallucinating) {
    ctx.log.warn('Workflow hallucination detected', { step: ctx.currentStep, score: result.confidence });
    return false;
  }
  return true;
}

import { ToolCallResult } from 'mastra/tools';
import { VexClient } from '@vex_dev/sdk';

const vex = new VexClient({ apiKey: process.env.VEX_API_KEY! });

export async function validateToolResponse(toolResult: ToolCallResult): Promise<boolean> {
  const schemaValidation = await vex.validateSchema({
    data: toolResult.output,
    expectedSchema: toolResult.tool.schema,
    context: toolResult.prompt
  });

  if (!schemaValidation.valid) {
    console.error('Tool response hallucination:', schemaValidation.errors);
    return false;
  }

  // Semantic validation against tool documentation
  const semanticCheck = await vex.checkGroundedness({
    response: JSON.stringify(toolResult.output),
    source: toolResult.tool.description
  });

  return semanticCheck.grounded;
}

import { MemoryContext } from 'mastra/memory';
import { VexClient } from '@vex_dev/sdk';

const vex = new VexClient({ apiKey: process.env.VEX_API_KEY! });

export async function validateMemoryContext(memory: MemoryContext): Promise<boolean> {
  const currentTimestamp = Date.now();
  const staleCutoff = currentTimestamp - 24 * 60 * 60 * 1000; // 24h

  for (const entry of memory.entries) {
    if (entry.timestamp < staleCutoff) {
      const freshnessCheck = await vex.checkTemporalConsistency({
        content: entry.content,
        timestamp: entry.timestamp,
        currentTime: currentTimestamp
      });

      if (!freshnessCheck.valid) {
        console.warn('Stale memory detected:', entry.id);
        return false;
      }
    }
  }

  return true;
}

