import { MastraAgent } from 'mastra';
import { VexMiddleware } from '@vex_dev/sdk/middleware';

const agent = new MastraAgent({
  name: 'production-agent',
  middleware: [
    VexMiddleware({
      apiKey: process.env.VEX_API_KEY!,
      detectors: ['hallucination', 'fact-check', 'schema-validation'],
      autoRemediate: true,
      failureMode: 'retry'
    })
  ]
});

export default agent;

import { WorkflowStep } from 'mastra/workflows';

export const groundedStep: WorkflowStep = {
  name: 'grounded-reasoning',
  instruction: `Always ground your response in the provided context. 
  If information is missing, say "I don't have that information".
  Format: { reasoning: "...", sources: ["source1", "source2"], answer: "..." }`,
  validator: async (output: any) => {
    return output.sources && output.sources.length > 0;
  },
  tools: ['fact_check', 'source_retrieval']
};

import { ToolCallResult } from 'mastra/tools';
import { VexClient } from '@vex_dev/sdk';

const vex = new VexClient();

export async function normalizeToolResponse(result: ToolCallResult): Promise<ToolCallResult> {
  if (!result.success) {
    const normalized = await vex.autoFix({
      type: 'tool_response',
      rawOutput: result.output,
      expectedSchema: result.tool.schema,
      context: result.prompt
    });

    return {
      ...result,
      output: normalized.fixedOutput,
      success: true
    };
  }
  return result;
}

