import { Mastra } from 'mastra';
import { Vex } from '@vex_dev/sdk';

// Initialize Mastra with Vex automation
const mastra = new Mastra({
  agents: ['./agents'],
  workflows: ['./workflows']
});

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  framework: 'mastra',
  autoMonitor: {
    hallucination: {
      enabled: true,
      threshold: 0.15,
      actions: ['retry', 'human-review']
    },
    tools: {
      enabled: true,
      validateSchema: true
    }
  }
});

// Auto-instrument all Mastra agents
vex.instrument(mastra);

// Production deployment
mastra.deploy();

// Vex provides real-time metrics
console.log('Hallucination detection active:', vex.metrics.hallucinationRate);
